cmg5sg6yw000vono4wt98gqma	Substance Misuse	substance-misuse	Evaluates problematic substance use patterns and potential substance use disorders.	[{"id": "substance_screening", "text": "Do you drink alcohol, vape/smoke nicotine, use marijuana or other THC products, use inhalants, hallucinogens, or amphetamines, take pills not prescribed to you, or use any other kind of substance recreationally?", "order": 1, "weight": 1, "skipLogic": {"skipToNextDomain": "NO"}, "isGatingQuestion": true}, {"id": "substance_1", "text": "Over your time using this substance, have you used it in larger amounts or over longer periods of time than you planned?", "order": 2, "weight": 1, "isGatingQuestion": false}, {"id": "substance_2", "text": "Have you wanted to or tried to stop or lessen your use of these substances and been unsuccessful?", "order": 3, "weight": 1, "isGatingQuestion": false}, {"id": "substance_3", "text": "Have you spent a great deal of time doing things to get these substances, use these substances, or recover from the effects of these substances?", "order": 4, "weight": 1, "isGatingQuestion": false}, {"id": "substance_4", "text": "Do you get strong cravings to use the substance?", "order": 5, "weight": 1, "isGatingQuestion": false}, {"id": "substance_5", "text": "Have you failed to meet certain responsibilities because of using this substance, for example forgetting to do chores, homework, work?", "order": 6, "weight": 1, "isGatingQuestion": false}, {"id": "substance_6", "text": "Have you continued using this substance despite it causing problems with friends, family, or meeting your responsibilities?", "order": 7, "weight": 1, "isGatingQuestion": false}, {"id": "substance_7", "text": "Have you given up, skipped out on, or left early from, or temporarily stepped away from important social, work, or fun activities to use the substance?", "order": 8, "weight": 1, "isGatingQuestion": false}, {"id": "substance_8", "text": "Have you used the substance in situations that are physically dangerous, for example while driving a car or riding with someone else while you were both under the influence?", "order": 9, "weight": 1, "isGatingQuestion": false}, {"id": "substance_9", "text": "Have you continued to use the substance despite knowing that it was having a negative effect on you?", "order": 10, "weight": 1, "isGatingQuestion": false}, {"id": "substance_10", "text": "Have you needed to use larger amounts of the substance to get the same effect, or noticed that the normal amount you use does not give you the same effect it once did?", "order": 11, "weight": 1, "isGatingQuestion": false}, {"id": "substance_11", "text": "Have you experienced any unpleasant feelings when you cannot use the substance, such as headaches, nausea, sweating, shaking, getting chilled, or have you used the substance to relieve or avoid these feelings?", "order": 12, "weight": 1, "isGatingQuestion": false}]	[{"url": null, "title": "Substance Use Disorder Information", "category": "information", "description": "Substance Use Disorders involve a problematic and increasing use of drugs, including alcohol. The user experiences an inability to stop, and often needs to increase their use to get the same effect."}]	{"maxScore": 11, "riskLevels": {"low": {"max": 1, "min": 0}, "high": {"max": 11, "min": 6}, "moderate": {"max": 5, "min": 2}}, "significantScore": 2}	7a79e16b-242f-4a34-b660-45d76273807a	2025-09-29 23:57:23.144	2025-09-29 23:57:23.144	1
cmg5sg6yy000zono4sc1awazj	Antisocial Personality	antisocial-personality	Evaluates patterns of disregard for and violation of the rights of others, assessed from age 15 and above.	[{"id": "aspd_age_check", "text": "Are you 15 years old or older?", "order": 1, "weight": 0, "isTrial": false, "skipLogic": {"skipToNextDomain": "NO"}, "isGatingQuestion": true}, {"id": "aspd_childhood_1", "text": "Before you were 15 years old, did you repeatedly skip school or run away from home overnight?", "order": 2, "weight": 1, "isTrial": false, "category": "childhood", "isGatingQuestion": false}, {"id": "aspd_childhood_2", "text": "Before you were 15 years old, did you repeatedly lie, cheat, 'con' others, or steal?", "order": 3, "weight": 1, "isTrial": false, "category": "childhood", "isGatingQuestion": false}, {"id": "aspd_childhood_3", "text": "Before you were 15 years old, did you start fights or bully, threaten, or intimidate others?", "order": 4, "weight": 1, "isTrial": false, "category": "childhood", "isGatingQuestion": false}, {"id": "aspd_childhood_4", "text": "Before you were 15 years old, did you purposefully destroy things or set fires?", "order": 5, "weight": 1, "isTrial": false, "category": "childhood", "isGatingQuestion": false}, {"id": "aspd_childhood_5", "text": "Before you were 15 years old, did you purposefully hurt animals or people?", "order": 6, "weight": 1, "isTrial": false, "category": "childhood", "isGatingQuestion": false}, {"id": "aspd_childhood_6", "text": "Before you were 15 years old, did you force someone to engage in sexual activity with you?", "order": 7, "weight": 1, "isTrial": false, "category": "childhood", "skipLogic": {"note": "If less than 2 childhood questions are YES, skip to next module", "skipToNextDomain": "LESS_THAN_TWO_YES"}, "isGatingQuestion": false}, {"id": "aspd_adult_1", "text": "Since you were 15 years old, have you repeatedly behaved in a way that others would consider irresponsible, like failing to pay for things you owed, deliberately being impulsive or deliberately not working to support yourself?", "order": 8, "weight": 1, "isTrial": false, "category": "adult", "isGatingQuestion": false}, {"id": "aspd_adult_2", "text": "Since you were 15 years old, have you done things that are illegal (for example, destroying property, shoplifting, stealing, selling drugs, or committing a felony)?", "order": 9, "weight": 1, "isTrial": false, "category": "adult", "isGatingQuestion": false}, {"id": "aspd_adult_3", "text": "Since you were 15 years old, have you been in physical fights repeatedly (including physical fights with friends or family)?", "order": 10, "weight": 1, "isTrial": false, "category": "adult", "isGatingQuestion": false}, {"id": "aspd_adult_4", "text": "Since you were 15 years old, have you often lied or tricked other people to get money or pleasure, or lied just for fun?", "order": 11, "weight": 1, "isTrial": false, "category": "adult", "isGatingQuestion": false}, {"id": "aspd_adult_5", "text": "Since you were 15 years old, have you exposed others to danger without caring?", "order": 12, "weight": 1, "isTrial": false, "category": "adult", "isGatingQuestion": false}, {"id": "aspd_adult_6", "text": "Since you were 15 years old, have you felt no guilt after hurting, mistreating, lying to, or stealing from others, or after damaging property?", "order": 13, "weight": 1, "isTrial": false, "category": "adult", "isGatingQuestion": false}]	[{"url": null, "title": "Antisocial Personality Information", "category": "information", "description": "Antisocial Personality Disorder cannot be officially diagnosed until an individual is 18 years of age; however, the patterns of behavior characteristic of this disorder emerge long before then."}]	{"maxScore": 12, "riskLevels": {"low": {"max": 4, "min": 0}, "high": {"max": 12, "min": 8}, "moderate": {"max": 7, "min": 5}}, "specialScoring": {"note": "Requires 2+ childhood criteria AND 3+ adult criteria for significant score", "requiresAdult": 3, "requiresChildhood": 2}, "significantScore": 5}	7a79e16b-242f-4a34-b660-45d76273807a	2025-09-29 23:57:23.146	2025-09-29 23:57:23.146	1
