cmg5sg6yu000rono4b2cbzkdc	Social Anxiety	social-anxiety	Evaluates fear and anxiety in social situations where judgment by others is possible.	[{"id": "social_1", "text": "Do you feel afraid or anxious about one or more social situations? For instance, talking to others, meeting new people, eating in public, or giving a speech?", "order": 1, "weight": 1, "isTrial": false, "skipLogic": {"skipToNextDomain": "NO"}, "isGatingQuestion": true}, {"id": "social_2", "text": "Is this feeling present even when the situation involves only your peers?", "order": 2, "weight": 1, "isTrial": false, "skipLogic": {"skipToNextDomain": "NO"}, "isGatingQuestion": true}, {"id": "social_3", "text": "Do you fear you will act in a way that others will judge you for in these situations?", "order": 3, "weight": 1, "isTrial": false, "isGatingQuestion": false}, {"id": "social_4", "text": "Do these social situations almost always provoke fear or anxiety?", "order": 4, "weight": 1, "isTrial": false, "isGatingQuestion": false}, {"id": "social_5", "text": "In these social situations, do you shrink away, freeze, stammer, cry, have difficulty talking, or become completely silent?", "order": 5, "weight": 1, "isTrial": false, "isGatingQuestion": false}, {"id": "social_6", "text": "Do you feel so afraid or anxious in these social situations that you try to avoid them or suffer through them when you can't avoid them?", "order": 6, "weight": 1, "isTrial": false, "isGatingQuestion": false}, {"id": "social_7", "text": "Would others consider this fear or anxiety excessive or unreasonable?", "order": 7, "weight": 1, "isTrial": false, "isGatingQuestion": false}, {"id": "social_8", "text": "Do these fears make your social life hard, cause you a lot of distress, or affect your ability/desire to go to school, go out in public, make friends, or make/keep plans with friends?", "order": 8, "weight": 1, "isTrial": false, "skipLogic": {"note": "If 3 items are coded as NO (excluding items 1 and 2), discontinue screening", "skipToNextDomain": "THREE_NO_ANSWERS"}, "isGatingQuestion": false}]	[{"url": null, "title": "Social Anxiety Information", "category": "information", "description": "Social Anxiety involves excessive anxiety and fear in social situations where the sufferer may be negatively evaluated by others."}]	{"maxScore": 8, "riskLevels": {"low": {"max": 5, "min": 0}, "high": {"max": 8, "min": 8}, "moderate": {"max": 7, "min": 6}}, "significantScore": 6}	7a79e16b-242f-4a34-b660-45d76273807a	2025-09-29 23:57:23.142	2025-09-29 23:57:23.142	1
cmg5sg6ys000nono45ie242p2	Generalized Anxiety	generalized-anxiety	Evaluates excessive worry and anxiety symptoms that interfere with daily functioning.	[{"id": "gad_1", "text": "Over the past 6 months, have you felt very worried or anxious about many things?", "order": 1, "weight": 1, "isTrial": false, "isGatingQuestion": true}, {"id": "gad_2", "text": "Are these worries present almost every day?", "order": 2, "weight": 1, "isTrial": false, "isGatingQuestion": true}, {"id": "gad_3", "text": "Is it hard to stop your worries or does worrying make it hard to focus on tasks?", "order": 3, "weight": 1, "isTrial": false, "skipLogic": {"requiresAny": ["gad_1", "gad_2", "gad_3"], "skipToNextDomain": "NO"}, "isGatingQuestion": true}, {"id": "gad_4", "text": "Over the past 6 months, when you were anxious, did you feel restless, excited, or on edge?", "order": 4, "weight": 1, "isTrial": false, "isGatingQuestion": false}, {"id": "gad_5", "text": "Over the past 6 months, when you were anxious, did you feel tense?", "order": 5, "weight": 1, "isTrial": false, "isGatingQuestion": false}, {"id": "gad_6", "text": "Over the past 6 months, when you were anxious, did you feel tired, weak, or easily exhausted?", "order": 6, "weight": 1, "isTrial": false, "isGatingQuestion": false}, {"id": "gad_7", "text": "Over the past 6 months, when you were anxious, did you have trouble concentrating or find your mind going blank?", "order": 7, "weight": 1, "isTrial": false, "isGatingQuestion": false}, {"id": "gad_8", "text": "Over the past 6 months, when you were anxious, did you feel irritated?", "order": 8, "weight": 1, "isTrial": false, "isGatingQuestion": false}, {"id": "gad_9", "text": "Over the past 6 months, when you were anxious, did you have trouble falling asleep, staying asleep, or waking up in the night or early morning, or sleeping much more than usual?", "order": 9, "weight": 1, "isTrial": false, "isGatingQuestion": false}, {"id": "gad_10", "text": "Over the past 6 months, when you were anxious, did you feel nauseous more than normal?", "order": 10, "weight": 1, "isTrial": false, "isGatingQuestion": false}, {"id": "gad_11", "text": "Over the past 6 months, when you were anxious, did you have recurring headaches?", "order": 11, "weight": 1, "isTrial": false, "isGatingQuestion": false}, {"id": "gad_12", "text": "Over the past 6 months, when you were anxious, did you expect the worst of something without reason?", "order": 12, "weight": 1, "isTrial": false, "isGatingQuestion": false}, {"id": "gad_13", "text": "Over the past 6 months, when you were anxious, did you become easily upset or feel easily overwhelmed by things that wouldn't upset or overwhelm others?", "order": 13, "weight": 1, "isTrial": false, "isGatingQuestion": false}]	[{"url": null, "title": "Generalized Anxiety Information", "category": "information", "description": "Generalized Anxiety involves excessive worrying about a wide range of topics and can be very distressing to those suffering from it."}]	{"maxScore": 13, "riskLevels": {"low": {"max": 4, "min": 0}, "high": {"max": 13, "min": 9}, "moderate": {"max": 8, "min": 5}}, "significantScore": 5}	7a79e16b-242f-4a34-b660-45d76273807a	2025-09-29 23:57:23.14	2025-09-29 23:57:23.14	1
