cmg5sg6yc0003ono4sd4zg9kr	Depression	depression	Evaluates symptoms related to Major Depressive Disorder including mood, sleep, appetite, and cognitive changes.	[{"id": "depression_1", "text": "Have you ever had a time in your life (including now) where you felt depressed or sad most of the day, every day, for nearly two weeks or more?", "order": 1, "weight": 1, "isTrial": false, "skipLogic": {"skipToNextDomain": "NO"}, "isGatingQuestion": true}, {"id": "depression_2", "text": "During that time, were you much hungrier or much less hungry nearly every day so that you gained or lost weight?", "order": 2, "weight": 1, "isTrial": false, "isGatingQuestion": false}, {"id": "depression_3", "text": "During that time, did you experience changes in your sleep, for example, trouble falling or staying asleep nearly every night, waking up much earlier than usual, or sleeping much more nearly every day?", "order": 3, "weight": 1, "isTrial": false, "isGatingQuestion": false}, {"id": "depression_4", "text": "During that time, did you talk or walk more slowly nearly every day?", "order": 4, "weight": 1, "isTrial": false, "isGatingQuestion": false}, {"id": "depression_5", "text": "During that time, were you more fidgety, restless, or have difficulty sitting still nearly every day?", "order": 5, "weight": 1, "isTrial": false, "isGatingQuestion": false}, {"id": "depression_6", "text": "During that time, did you feel much more tired nearly every day?", "order": 6, "weight": 1, "isTrial": false, "isGatingQuestion": false}, {"id": "depression_7", "text": "During that time, did you have trouble paying attention or making decisions nearly every day?", "order": 7, "weight": 1, "isTrial": false, "isGatingQuestion": false}, {"id": "depression_8", "text": "During that time, did you feel much more irritable, easily frustrated, upset, or short-tempered nearly every day- maybe even to the point where you got into arguments or fights with others?", "order": 8, "weight": 1, "isTrial": false, "isGatingQuestion": false}, {"id": "depression_9", "text": "During that time, did you feel so unhappy that you didn't want to do anything, or stopped doing things you enjoyed?", "order": 9, "weight": 1, "isTrial": false, "isGatingQuestion": false}]	[{"url": null, "title": "Depression Information", "category": "information", "description": "The Depression Screen asks questions related to Major Depressive Disorder. While not designed to diagnose Major Depressive Disorder or to provide a full risk assessment for the disorder, endorsement of these criteria could signal the presence of a current or emerging problem in this domain."}, {"url": null, "title": "Crisis Resources", "category": "crisis", "description": "If you are having thoughts of suicide or self-harm, you should reach out to your Primary Care Provider or a mental health professional. Additionally, numbers like 9-1-1, and 9-8-8 can be used in suicidal or crisis situations."}]	{"maxScore": 9, "riskLevels": {"low": {"max": 3, "min": 0}, "high": {"max": 9, "min": 7}, "moderate": {"max": 6, "min": 4}}, "significantScore": 4}	7a79e16b-242f-4a34-b660-45d76273807a	2025-09-29 23:57:23.125	2025-09-29 23:57:23.125	1
